SET SESSION TRANSACTION ISOLATION LEVEL REPEATABLE READ;

START TRANSACTION;
SELECT balance FROM accounts WHERE id = 1;  -- Returns: 1000
-- Another transaction updates balance to 900 and commits
SELECT balance FROM accounts WHERE id = 1;  -- Still returns: 1000 (snapshot)
COMMIT;

SET SESSION TRANSACTION ISOLATION LEVEL READ COMMITTED;

START TRANSACTION;
SELECT COUNT(*) FROM orders;  -- Returns: 100
-- Another session inserts and commits a new order
SELECT COUNT(*) FROM orders;  -- Returns: 101 (sees committed changes)
COMMIT;

SET SESSION TRANSACTION ISOLATION LEVEL SERIALIZABLE;

START TRANSACTION;
SELECT * FROM accounts WHERE balance > 1000;
-- Returns 5 rows
-- Other transactions BLOCKED from inserting matching rows
SELECT * FROM accounts WHERE balance > 1000;
-- Still exactly 5 rows (phantom reads prevented)
COMMIT;

common_mistakes.error_sql:
-- Using REPEATABLE READ
START TRANSACTION;
SELECT * FROM products WHERE category = 'electronics';
-- Returns 10 rows
-- Another transaction INSERTs new electronics product and commits
SELECT * FROM products WHERE category = 'electronics';
-- Still 10 rows, but application expects to see new row

common_mistakes.fix_sql:
SET SESSION TRANSACTION ISOLATION LEVEL READ COMMITTED;
START TRANSACTION;
-- Or commit/restart transaction to get fresh snapshot

common_mistakes.error_sql:
-- Transaction A
SET SESSION TRANSACTION ISOLATION LEVEL SERIALIZABLE;
START TRANSACTION;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
-- Meanwhile Transaction B does the reverse...
-- DEADLOCK!

common_mistakes.fix_sql:
-- Use lower isolation level if full serializability isn't required
SET SESSION TRANSACTION ISOLATION LEVEL REPEATABLE READ;

-- Or ensure consistent lock ordering (always lock id 1 before id 2)

