CREATE TRIGGER check_customer_limit
BEFORE INSERT ON orders
FOR EACH ROW
BEGIN
    DECLARE v_count INT;
    SELECT COUNT(*) INTO v_count FROM orders
    WHERE customer_id = NEW.customer_id;
    IF v_count > 100 THEN
        SIGNAL SQLSTATE '45000';
    END IF;
END;

